1647       match(RHS, m_BinOp(m_Value(Z), m_Value(W)))) {
1648     auto *BO = cast<BinaryOperator>(LHS);
1649     // Don't introduce poison into div/rem.
1650     if (llvm::is_contained(OldMask, PoisonMaskElem) && BO->isIntDivRem())
1651       return false;
1652     IsCommutative = BinaryOperator::isCommutative(BO->getOpcode());
1653   } else if (match(LHS, m_Cmp(Pred, m_Value(X), m_Value(Y))) &&
1654              match(RHS, m_SpecificCmp(Pred, m_Value(Z), m_Value(W)))) {
1655     IsCommutative = cast<CmpInst>(LHS)->isCommutative();
1656   } else
1657     return false;
1658 
1659   auto *ShuffleDstTy = dyn_cast<FixedVectorType>(I.getType());
1660   auto *BinResTy = dyn_cast<FixedVectorType>(LHS->getType());
1661   auto *BinOpTy = dyn_cast<FixedVectorType>(X->getType());
1662   if (!ShuffleDstTy || !BinResTy || !BinOpTy || X->getType() != Z->getType())
1663     return false;
1664 
1665   unsigned NumSrcElts = BinOpTy->getNumElements();
1666 
1667   // If we have something like "add X, Y" and "add Z, X", swap ops to match.
1668   if (IsCommutative && X != Z && Y != W && (X == W || Y == Z))
1669     std::swap(X, Y);
1670 
1671   auto ConvertToUnary = [NumSrcElts](int &M) {
1672     if (M >= (int)NumSrcElts)
1673       M -= NumSrcElts;
1674   };
