1676   SmallVector<int> NewMask0(OldMask);
1677   TargetTransformInfo::ShuffleKind SK0 = TargetTransformInfo::SK_PermuteTwoSrc;
1678   if (X == Z) {
1679     llvm::for_each(NewMask0, ConvertToUnary);
1680     SK0 = TargetTransformInfo::SK_PermuteSingleSrc;
1681     Z = PoisonValue::get(BinOpTy);
1682   }
1683 
1684   SmallVector<int> NewMask1(OldMask);
1685   TargetTransformInfo::ShuffleKind SK1 = TargetTransformInfo::SK_PermuteTwoSrc;
1686   if (Y == W) {
1687     llvm::for_each(NewMask1, ConvertToUnary);
1688     SK1 = TargetTransformInfo::SK_PermuteSingleSrc;
1689     W = PoisonValue::get(BinOpTy);
1690   }
1691 
1692   // Try to replace a binop with a shuffle if the shuffle is not costly.
1693   InstructionCost OldCost =
1694       TTI.getInstructionCost(LHS, CostKind) +
1695       TTI.getInstructionCost(RHS, CostKind) +
1696       TTI.getShuffleCost(TargetTransformInfo::SK_PermuteTwoSrc, BinResTy,
1697                          OldMask, CostKind, 0, nullptr, {LHS, RHS}, &I);
1698 
