1625 // Same as CmpClass, but instead of saving Pred as out output variable, match a
1626 // specific input pred for equality.
1627 template <typename LHS_t, typename RHS_t, typename Class,
1628           bool Commutable = false>
1629 struct SpecificCmpClass_match {
1630   const CmpPredicate Predicate;
1631   LHS_t L;
1632   RHS_t R;
1633 
1634   SpecificCmpClass_match(CmpPredicate Pred, const LHS_t &LHS, const RHS_t &RHS)
1635       : Predicate(Pred), L(LHS), R(RHS) {}
1636 
1637   template <typename OpTy> bool match(OpTy *V) {
1638     if (auto *I = dyn_cast<Class>(V)) {
1639       if (CmpPredicate::getMatching(CmpPredicate::get(I), Predicate) &&
1640           L.match(I->getOperand(0)) && R.match(I->getOperand(1)))
1641         return true;
1642       if constexpr (Commutable) {
1643         if (CmpPredicate::getMatching(CmpPredicate::get(I),
1644                                       CmpPredicate::getSwapped(Predicate)) &&
1645             L.match(I->getOperand(1)) && R.match(I->getOperand(0)))
1646           return true;
1647       }
1648     }
1649 
1650     return false;
1651   }
1652 };
